  // ==================== Data Integrity ====================

  Future<void> _updateIntegrityHash() async {
    final sensitiveKeys = [
      _StorageKeys.authTokens,
      _StorageKeys.userProfile,
    ];

    final buffer = StringBuffer();
    for (final key in sensitiveKeys) {
      final value = _safePrefs.getString(key);
      if (value != null) {
        buffer.write('$key:$value;');
      }
    }

    final hash =
        sha256.convert(utf8.encode(buffer.toString())).toString();
    await _safePrefs.setString(_StorageKeys.dataIntegrityHash, hash);
  }

  bool verifyDataIntegrity() {
    try {
      final storedHash =
          _safePrefs.getString(_StorageKeys.dataIntegrityHash);
      if (storedHash == null) return true; // No hash stored yet

      final sensitiveKeys = [
        _StorageKeys.authTokens,
        _StorageKeys.userProfile,
      ];

      final buffer = StringBuffer();
      for (final key in sensitiveKeys) {
        final value = _safePrefs.getString(key);
        if (value != null) {
          buffer.write('$key:$value;');
        }
      }

      final computedHash =
          sha256.convert(utf8.encode(buffer.toString())).toString();
      return storedHash == computedHash;
    } catch (e) {
      debugPrint('Data integrity check failed: $e');
      return false;
    }
  }

  // ==================== Cache Index Management ====================

  List<String> _getCacheIndex() {
    final indexJson = _safePrefs.getString(_StorageKeys.cacheIndex);
    if (indexJson == null) return [];
    try {
      return (jsonDecode(indexJson) as List<dynamic>).cast<String>();
    } catch (e) {
      return [];
    }
  }

  Future<void> _addToCacheIndex(String key) async {
    final index = _getCacheIndex();
    if (!index.contains(key)) {
      index.add(key);
      await _safePrefs.setString(_StorageKeys.cacheIndex, jsonEncode(index));
    }
  }

  Future<void> _removeFromCacheIndex(String key) async {
    final index = _getCacheIndex();
    index.remove(key);
    await _safePrefs.setString(_StorageKeys.cacheIndex, jsonEncode(index));
  }

  Future<void> _cleanExpiredCache() async {
    final index = _getCacheIndex();
    final keysToRemove = <String>[];

    for (final key in index) {
      final storageKey = '${_StorageKeys.cachePrefix}$key';
      final jsonString = _safePrefs.getString(storageKey);
      if (jsonString == null) {
        keysToRemove.add(key);
        continue;
      }

      try {
        final json = jsonDecode(jsonString) as Map<String, dynamic>;
        final cached = CachedContent.fromJson(json);
        if (cached.isExpired) {
          keysToRemove.add(key);
          await _safePrefs.remove(storageKey);
        }
      } catch (e) {
        keysToRemove.add(key);
        await _safePrefs.remove(storageKey);
      }
    }

    if (keysToRemove.isNotEmpty) {
      final updatedIndex =
          index.where((k) => !keysToRemove.contains(k)).toList();
      await _safePrefs.setString(
          _StorageKeys.cacheIndex, jsonEncode(updatedIndex));
      debugPrint('Cleaned ${keysToRemove.length} expired cache entries');
    }
  }

  // ==================== Utility Methods ====================

  String _sanitizeString(String input) {
    return input.trim().replaceAll(RegExp(r'[^\w\-_.]'), '');
  }

  String _sanitizeCacheKey(String key) {
    final sanitized = key.trim().replaceAll(RegExp(r'[^\w\-_./:]'), '_');
    if (sanitized.isEmpty) {
      throw StorageException('Cache key cannot be empty');
    }
    if (sanitized.length > 256) {
      // Use hash for very long keys
      return sha256.convert(utf8.encode(key)).toString().substring(0, 32);
    }
    return sanitized;
  }

  // Debug helper
  Map<String, dynamic> getStorageSummary() {
    return {
      'initialized': _initialized,
      'isAuthenticated': _initialized ? isAuthenticated : false,
      'hasUserProfile': _initialized ? getUserProfile() != null : false,
      'cacheSize': _initialized ? getCacheSize() : 0,
      'lastSync': _initialized ? getLastSyncTimestamp()?.toIso8601String() : null,
      'themeMode': _initialized ? getThemeMode() : null,
      'locale': _initialized ? getLocale() : null,
      'dataIntegrityValid': _initialized ? verifyDataIntegrity() : false,
    };
  }
}

// Convenience extension for quick access
extension LocalStorageQuickAccess on LocalStorageManager {
  /// Get authorization header value
  String? get authorizationHeader {
    final tokens = getAuthTokens();
    if (tokens == null || tokens.isExpired) return null;
    return '${tokens.tokenType} ${tokens.accessToken}';
  }

  /// Get user display name
  String? get userDisplayName => getUserProfile()?.name;

  /// Get user email
  String? get userEmail => getUserProfile()?.email;

  /// Get API base URL from config
  String get apiBaseUrl => getAppConfig().apiBaseUrl;

  /// Check if dark mode
  bool get isDarkMode => getThemeMode() == 'dark';

  /// Quick save and retrieve generic preferences
  Future<void> setPreference(String key, dynamic value) async {
    final prefs = _safePrefs;
    final prefKey = 'custom_pref_$key';
    if (value is String) {
      await prefs.setString(prefKey, value);
    } else if (value is int) {
      await prefs.setInt(prefKey, value);
    } else if (value is double) {
      await prefs.setDouble(prefKey, value);
    } else if (value is bool) {
      await prefs.setBool(prefKey, value);
    } else if (value is List<String>) {
      await prefs.setStringList(prefKey, value);
    } else {
      throw StorageException('Unsupported preference type: ${value.runtimeType}');
    }
  }

  T? getPreference<T>(String key) {
    final prefKey = 'custom_pref_$key';
    return _safePrefs.get(prefKey) as T?;
  }
}

