  // Save app config
  await storage.saveAppConfig(AppConfig(
    apiBaseUrl: 'https://api.production.com',
    cacheExpirationMinutes: 120,
    analyticsEnabled: true,
    appVersion: '2.1.0',
    featureFlags: {
      'dark_mode': true,
      'new_dashboard': false,
    },
  ));

  // Set preferences
  await storage.setThemeMode('dark');
  await storage.setLocale('en');
  await storage.setNotificationsEnabled(true);
  await storage.setFontSize(16.0);

  // Cache content
  await storage.cacheContent(
    'home_feed',
    data: jsonEncode({'posts': []}),
    ttl: const Duration(minutes: 30),
  );

  await storage.cacheJsonContent(
    'user_settings',
    data: {'notifications': true, 'language': 'en'},
    ttl: const Duration(hours: 24),
  );

  // Quick access
  debugPrint('Auth header: ${storage.authorizationHeader}');
  debugPrint('User: ${storage.userDisplayName}');
  debugPrint('API URL: ${storage.apiBaseUrl}');
  debugPrint('Is dark mode: ${storage.isDarkMode}');
  debugPrint('Feature enabled: ${storage.isFeatureEnabled('dark_mode')}');
  debugPrint('Needs sync: ${storage.needsSync()}');
  debugPrint('Data integrity: ${storage.verifyDataIntegrity()}');

  // Read cached content
  final feed = storage.getCachedContent('home_feed');
  debugPrint('Cached feed: $feed');

  final settings = storage.getCachedJsonContent('user_settings');
  debugPrint('Cached settings: $settings');

  // Storage summary
  debugPrint('Summary: ${storage.getStorageSummary()}');
}